exec("""from __future__ import annotations\nimport json\nfrom dataclasses import asdict\nfrom datetime import datetime, timedelta, timezone\nfrom src.enoking_scraper import DEFAULT_BASE_URL, crawl_enoking_products, product_to_dict, write_outputs\nfrom src.supplier_discovery import generate_opportunities, write_opportunities\nfrom src.site_builder import build_static_site\nJST = timezone(timedelta(hours=9), 'JST')\ndef run_pipeline():\n    products = crawl_enoking_products(DEFAULT_BASE_URL); product_paths = write_outputs(products); rows = [product_to_dict(p) for p in products]; opportunities = generate_opportunities(rows); opportunity_paths = write_opportunities(opportunities); site_metadata = build_static_site(); return {'finished_at_jst': datetime.now(JST).strftime('%Y-%m-%d %H:%M:%S %Z'), 'product_count': len(products), 'opportunity_count': len(opportunities), 'product_outputs': product_paths, 'opportunity_outputs': opportunity_paths, 'site_metadata': site_metadata, 'top_opportunities': [asdict(o) for o in opportunities[:10]]}\ndef main():\n    print(json.dumps(run_pipeline(), ensure_ascii=False, indent=2)); return 0\nif __name__ == '__main__':\n    raise SystemExit(main())\n""")